import MasonryGrid from "./MasonryGrid";

const Galeria = () => {
  return (
    <section className="min-h-screen bg-[#D8C4A5] py-32">

      <div className="text-center mb-16">
        <h1 className="text-4xl font-bold text-[#7A5C3A]">
          ¿Te quedaste con ganas de ver más?
        </h1>

        <div className="h-[5px] w-[220px] mx-auto mt-3 bg-gradient-to-r from-[#CC2329] to-[#F55809] rounded-full"></div>
      </div>

      <div className="w-[55%] mx-auto">
        <MasonryGrid />
      </div>

    </section>
  );
};

export default Galeria;
